package com.loosenotes.util;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.servlet.http.HttpSession;
import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;

/**
 * CSRF token management utilities.
 *
 * <p>Tokens are 128-bit (32 hex characters) values generated by
 * {@link TokenUtil#generateToken128Bit()} and stored in the HTTP session
 * under the key {@code "csrfToken"}. Token comparison is performed using a
 * constant-time algorithm to prevent timing-based enumeration of valid token
 * bytes.</p>
 *
 * <p>Callers should rotate the token after each successful state-changing
 * request to limit the window of opportunity for token reuse.</p>
 */
public final class CsrfUtil {

    private static final Logger log = LoggerFactory.getLogger(CsrfUtil.class);

    /** Session attribute key under which the current CSRF token is stored. */
    public static final String SESSION_ATTR = "csrfToken";

    private CsrfUtil() {
        // utility class — no instantiation
    }

    /**
     * Return the current session CSRF token, creating a new one if none exists.
     *
     * @param session the active HTTP session; must not be null
     * @return the 32-character hexadecimal CSRF token for this session
     * @throws IllegalArgumentException if {@code session} is null
     */
    public static String getOrCreateToken(HttpSession session) {
        if (session == null) {
            throw new IllegalArgumentException("session must not be null");
        }

        String existing = (String) session.getAttribute(SESSION_ATTR);
        if (existing != null && !existing.isEmpty()) {
            return existing;
        }

        String newToken = TokenUtil.generateToken128Bit();
        session.setAttribute(SESSION_ATTR, newToken);
        log.debug("CSRF token created for session id={}", obfuscateSessionId(session.getId()));
        return newToken;
    }

    /**
     * Validate a submitted CSRF token against the value stored in the session.
     *
     * <p>Comparison is performed using {@link MessageDigest#isEqual(byte[], byte[])}
     * which operates in constant time regardless of where the bytes first differ,
     * preventing timing-based token oracle attacks.</p>
     *
     * @param session        the active HTTP session; null returns false
     * @param submittedToken the token value extracted from the request parameter; null returns false
     * @return {@code true} if both tokens are non-null and equal
     */
    public static boolean validateToken(HttpSession session, String submittedToken) {
        if (session == null || submittedToken == null) {
            log.warn("CSRF validation failed: null session or submitted token");
            return false;
        }

        String sessionToken = (String) session.getAttribute(SESSION_ATTR);
        if (sessionToken == null || sessionToken.isEmpty()) {
            log.warn("CSRF validation failed: no token in session");
            return false;
        }

        // Constant-time comparison — prevents timing side-channels.
        byte[] sessionBytes = sessionToken.getBytes(StandardCharsets.UTF_8);
        byte[] submittedBytes = submittedToken.getBytes(StandardCharsets.UTF_8);

        boolean valid = MessageDigest.isEqual(sessionBytes, submittedBytes);
        if (!valid) {
            log.warn("CSRF validation failed: token mismatch for session id={}",
                    obfuscateSessionId(session.getId()));
        }
        return valid;
    }

    /**
     * Invalidate the current session CSRF token and replace it with a fresh one.
     *
     * <p>Rotation should be performed after each successful POST/PUT/DELETE to
     * prevent token-reuse attacks in the event of a prior token leak.</p>
     *
     * @param session the active HTTP session; must not be null
     * @throws IllegalArgumentException if {@code session} is null
     */
    public static void rotateToken(HttpSession session) {
        if (session == null) {
            throw new IllegalArgumentException("session must not be null");
        }

        String newToken = TokenUtil.generateToken128Bit();
        session.setAttribute(SESSION_ATTR, newToken);
        log.debug("CSRF token rotated for session id={}", obfuscateSessionId(session.getId()));
    }

    // -------------------------------------------------------------------------
    // Internal helpers
    // -------------------------------------------------------------------------

    /**
     * Produce a log-safe representation of a session ID: first 8 characters
     * followed by "…" to prevent full session IDs from appearing in logs.
     */
    private static String obfuscateSessionId(String sessionId) {
        if (sessionId == null || sessionId.length() <= 8) {
            return "***";
        }
        return sessionId.substring(0, 8) + "…";
    }
}
